glT(){return"\u041f\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0432\u0435\u0440\u0445\u043d\u0438\u0439 \u043f\u0440\u0430\u0432\u044b\u0439 \u0431\u043b\u043e\u043a. \u0414\u0432\u0435 \u044f\u0447\u0435\u0439\u043a\u0438 \u0438\u043c\u0435\u044e\u0442 \u0440\u043e\u0432\u043d\u043e \u043e\u0434\u043d\u0443 \u0438 \u0442\u0443 \u0436\u0435 \u043f\u0430\u0440\u0443 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432: [1, 2]. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u044d\u0442\u0443 \u0433\u043e\u043b\u0443\u044e \u043f\u0430\u0440\u0443, \u0447\u0442\u043e\u0431\u044b \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u044c \u044d\u0442\u0438\u0445 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432 \u0438\u0437 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u0443\u0441\u0442\u044b\u0445 \u044f\u0447\u0435\u0435\u043a \u044d\u0442\u043e\u0433\u043e \u0431\u043b\u043e\u043a\u0430."},
glS(){return"\u0413\u043e\u043b\u0430\u044f \u043f\u0430\u0440\u0430 [1, 2] \u0432 R1C8 \u0438 R1C9 \u2014 \u0438\u0441\u043a\u043b\u044e\u0447\u0430\u0435\u043c \u044d\u0442\u0438 \u0446\u0438\u0444\u0440\u044b \u0438\u0437 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u0447\u0430\u0441\u0442\u0438 \u0431\u043b\u043e\u043a\u0430 (R1\u2013R3, C7\u2013C9)"},
gmy(){return"\u0413\u043e\u043b\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0441\u0442\u0440\u043e\u043a\u0430"},
gmx(){return"\u0421\u0442\u0440\u043e\u043a\u0430"},
gmw(){return"\u0412 \u043e\u0434\u043d\u043e\u0439 \u044f\u0447\u0435\u0439\u043a\u0435 \u044d\u0442\u043e\u0439 \u0441\u0442\u0440\u043e\u043a\u0438 \u043e\u0441\u0442\u0430\u043b\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0434\u0438\u043d \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442. \u0412\u0441\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0446\u0438\u0444\u0440\u044b \u043e\u0442 1 \u0434\u043e 6 \u0443\u0436\u0435 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044e\u0442\u0441\u044f \u0432 \u0435\u0451 \u0441\u0442\u0440\u043e\u043a\u0435, \u0441\u0442\u043e\u043b\u0431\u0446\u0435 \u0438\u043b\u0438 \u0431\u043b\u043e\u043a\u0435. \u041d\u0430\u0439\u0434\u0438\u0442\u0435 \u043f\u0443\u0441\u0442\u0443\u044e \u044f\u0447\u0435\u0439\u043a\u0443 \u0438 \u0446\u0438\u0444\u0440\u0443, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u043e\u043d\u0430 \u0434\u043e\u043b\u0436\u043d\u0430 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0442\u044c."},
