gme(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0441\u0442\u043e\u043b\u0431\u0435\u0446"},
gmd(){return"\u0421\u0442\u043e\u043b\u0431\u0435\u0446"},
gmc(){return"\u041f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u044d\u0442\u043e\u0442 \u0441\u0442\u043e\u043b\u0431\u0435\u0446 \u0432 \u043f\u043e\u0438\u0441\u043a\u0430\u0445 \u0446\u0438\u0444\u0440\u044b 6. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u044f\u0447\u0435\u0435\u043a \u043f\u0443\u0441\u0442\u044b, \u043d\u043e 6 \u043f\u043e\u043c\u0435\u0449\u0430\u0435\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u043e\u0434\u043d\u0443 \u0438\u0437 \u043d\u0438\u0445 \u2014 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0437\u0430\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u043d\u044b \u0441\u0432\u043e\u0438\u043c\u0438 \u0441\u0442\u0440\u043e\u043a\u0430\u043c\u0438 \u0438\u043b\u0438 \u0431\u043b\u043e\u043a\u0430\u043c\u0438."},
gmb(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u0432 R2C2 \u2014 6 \u043c\u043e\u0436\u0435\u0442 \u0441\u0442\u043e\u044f\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0434\u0435\u0441\u044c \u0432 \u0441\u0442\u043e\u043b\u0431\u0446\u0435 2"},
gmi(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0431\u043b\u043e\u043a"},
gmh(){return"\u0411\u043b\u043e\u043a"},
gmg(){return"\u041f\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0431\u043b\u043e\u043a 2\xd73 \u0441\u043f\u0440\u0430\u0432\u0430. \u0426\u0438\u0444\u0440\u0430 4 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u043c\u0435\u0441\u0442\u0438\u0442\u044c\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u043e\u0434\u043d\u0443 \u0438\u0437 \u0435\u0433\u043e \u043f\u0443\u0441\u0442\u044b\u0445 \u044f\u0447\u0435\u0435\u043a; \u043b\u044e\u0431\u043e\u0435 \u0434\u0440\u0443\u0433\u043e\u0435 \u043c\u0435\u0441\u0442\u043e \u0432 \u0431\u043b\u043e\u043a\u0435 \u0437\u0430\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u043d\u043e \u0441\u0442\u0440\u043e\u043a\u043e\u0439 \u0438\u043b\u0438 \u0441\u0442\u043e\u043b\u0431\u0446\u043e\u043c. \u041d\u0430\u0439\u0434\u0438\u0442\u0435 \u0435\u0451."},
gmf(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u0432 R4C6 \u2014 4 \u043c\u043e\u0436\u0435\u0442 \u0441\u0442\u043e\u044f\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0434\u0435\u0441\u044c \u0432 region 4"},
gmm(){return"\u0413\u043e\u043b\u0430\u044f \u043f\u0430\u0440\u0430 \u2014 \u0441\u0442\u0440\u043e\u043a\u0430"},
gml(){return"\u0421\u0442\u0440\u043e\u043a\u0430"},
gmk(){return"\u0412\u043e \u0432\u0442\u043e\u0440\u043e\u0439 \u0441\u0442\u0440\u043e\u043a\u0435 \u0434\u0432\u0435 \u044f\u0447\u0435\u0439\u043a\u0438 \u0438\u043c\u0435\u044e\u0442 \u0440\u043e\u0432\u043d\u043e \u043e\u0434\u043d\u0443 \u0438 \u0442\u0443 \u0436\u0435 \u043f\u0430\u0440\u0443 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432: [1, 5]. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u044d\u0442\u0438 \u0434\u0432\u0435 \u0446\u0438\u0444\u0440\u044b \u0437\u0430\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u043d\u044b \u0432 \u044d\u0442\u0438\u0445 \u0434\u0432\u0443\u0445 \u044f\u0447\u0435\u0439\u043a\u0430\u0445, \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u044c 1 \u0438 5 \u0438\u0437 \u0432\u0441\u0435\u0445 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u0443\u0441\u0442\u044b\u0445 \u044f\u0447\u0435\u0435\u043a \u0441\u0442\u0440\u043e\u043a\u0438. \u041d\u0430\u0439\u0434\u0438\u0442\u0435 \u043f\u0430\u0440\u0443."},
gmj(){return"\u0413\u043e\u043b\u0430\u044f \u043f\u0430\u0440\u0430 [1, 5] \u0432 R2C2 \u0438 R2C3 \u2014 \u0438\u0441\u043a\u043b\u044e\u0447\u0430\u0435\u043c \u044d\u0442\u0438 \u0446\u0438\u0444\u0440\u044b \u0438\u0437 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u0447\u0430\u0441\u0442\u0438 \u0441\u0442\u0440\u043e\u043a\u0438 2"},
gmq(){return"\u0413\u043e\u043b\u0430\u044f \u043f\u0430\u0440\u0430 \u2014 \u0441\u0442\u043e\u043b\u0431\u0435\u0446"},
gmp(){return"\u0421\u0442\u043e\u043b\u0431\u0435\u0446"},
gmo(){return"\u041f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439 \u0441\u0442\u043e\u043b\u0431\u0435\u0446. \u0414\u0432\u0435 \u044f\u0447\u0435\u0439\u043a\u0438 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0442 \u0440\u043e\u0432\u043d\u043e \u043e\u0434\u043d\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u0434\u0432\u0430 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u0430: [2, 5]. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 2 \u0438 5 \u0434\u043e\u043b\u0436\u043d\u044b \u0437\u0430\u043d\u0438\u043c\u0430\u0442\u044c \u044d\u0442\u0438 \u0434\u0432\u0435 \u044f\u0447\u0435\u0439\u043a\u0438, \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u0435 \u0438\u0445 \u0438\u0437 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u0443\u0441\u0442\u044b\u0445 \u044f\u0447\u0435\u0435\u043a \u0441\u0442\u043e\u043b\u0431\u0446\u0430."},
gmn(){return"\u0413\u043e\u043b\u0430\u044f \u043f\u0430\u0440\u0430 [2, 5] \u0432 R3C6 \u0438 R4C6 \u2014 \u0438\u0441\u043a\u043b\u044e\u0447\u0430\u0435\u043c \u044d\u0442\u0438 \u0446\u0438\u0444\u0440\u044b \u0438\u0437 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u0447\u0430\u0441\u0442\u0438 \u0441\u0442\u043e\u043b\u0431\u0446\u0430 6"},
